What does the following program print?

```cpp
#include <iostream>
int main()
{
    int x = 3;
    switch (x)
    {
        case 1: std::cout << "one\n"; break;
        case 2: std::cout << "two\n"; break;
        case 3: std::cout << "three\n";
        case 4: std::cout << "four\n"; break;
        default: std::cout << "other\n"; break;
    }
}
```

What does the following program print?

```cpp
#include <iostream>
int main()
{
    for (int i = 0; i < 5; ++i)
    {
        if (i == 3)
            break;
        if (i % 2 == 0)
            continue;
        std::cout << i << '\n';
    }
}
```

